Archivo: /etc/phpldapadmin/config.php

PARAMETROS CLAVE:

1. Nombre del servidor:
$ldapservers->SetValue($i,'server','name','Mi Servidor LDAP');

2. Direccion del servidor:
$ldapservers->SetValue($i,'server','host','127.0.0.1');

3. Puerto LDAP:
$ldapservers->SetValue($i,'server','port','389');

4. DN base:
$ldapservers->SetValue($i,'server','base',array('dc=example,dc=com'));

5. Cadena de login:
$ldapservers->SetValue($i,'login','string','uid=<username>,ou=People,dc=example,dc=com');
